function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);

    // Helper function to check if a subarray can be sorted by cyclic shifts
    // A subarray can be sorted by cyclic shifts if and only if it is a cyclic shift
    // of its sorted version. This is equivalent to checking if the multiset
    // of elements in the subarray is the same as the multiset of elements in its sorted form,
    // and for a single block, it just means it must contain the right elements.
    // Since we are dealing with partitioning the entire array, the multiset condition is always met
    // if we consider the whole array.
    // For a single block of size k, if it can be sorted, it means the elements
    // must be permutable into the sorted order by cyclic shifts.
    // This is true if and only if the elements are already in order or are a cyclic shift of the sorted order.

    /**
     * Checks if array 'arr' can be sorted into 'target' using cyclic shifts.
     * Since the elements in a block are fixed, 'target' is the sorted version of 'arr'.
     * The elements in 'arr' can be sorted via cyclic shifts if and only if 'arr' is a cyclic shift of 'target'.
     * @param {number[]} arr The subarray.
     * @param {number[]} target The sorted version of the subarray.
     * @returns {boolean} True if arr is a cyclic shift of target.
     */
    const isCyclicShift = (arr, target) => {
        if (arr.length === 0) return true;
        const len = arr.length;

        // Concatenate target with itself to check for circular substring/subarray match
        const doubleTarget = [...target, ...target];

        // Check all possible starting points in doubleTarget
        for (let start = 0; start < len; start++) {
            let match = true;
            for (let i = 0; i < len; i++) {
                if (arr[i] !== doubleTarget[start + i]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }
        return false;
    };

    /**
     * Checks if a given divisor k allows sorting the array nums.
     * @param {number} k The potential divisor.
     * @returns {boolean} True if k is a "sortable integer".
     */
    const checkK = (k) => {
        if (k === 0 || n % k !== 0) return false;

        const numBlocks = n / k;
        let allBlocksSortable = true;

        for (let i = 0; i < numBlocks; i++) {
            const start = i * k;
            const end = start + k;
            const block = nums.slice(start, end);

            // The target for this block is the corresponding segment of sortedNums
            const targetBlock = sortedNums.slice(start, end);

            // Check if this block can be cyclically shifted to match its sorted target
            if (!isCyclicShift(block, targetBlock)) {
                allBlocksSortable = false;
                break;
            }
        }

        return allBlocksSortable;
    };

    let sumOfK = 0;

    // Find all divisors k of n
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            const divisors = [k];
            if (k * k !== n) {
                divisors.push(n / k);
            }

            for (const divisor of divisors) {
                if (checkK(divisor)) {
                    sumOfK += divisor;
                }
            }
        }
    }

    return sumOfK;
}

